import { Effect } from "effect";
import { Value } from "@sinclair/typebox/value";
import * as YAML from "yaml";
import { BundleDecodeCause, BundleDecodeError } from "../core/errors.js";
import { JudgmentBundleSchema, formatSchemaErrors, type JudgmentBundleStatic } from "../core/schema.js";
import {
  AgentId,
  ProjectId,
  RunId,
  ScenarioId,
  type AgentOutcome,
  type AgentRef,
  type AgentTurn,
  type JudgmentBundle as JudgmentBundleType,
} from "../core/types.js";

export interface BundleCodec {
  readonly name: string;
  encode(bundle: JudgmentBundleType): Effect.Effect<string, never, never>;
  decode(source: string, originPath: string): Effect.Effect<JudgmentBundleType, BundleDecodeError, never>;
}

function decodeFromParsed(parsed: unknown, originPath: string): Effect.Effect<JudgmentBundleType, BundleDecodeError, never> {
  const errors = formatSchemaErrors(Value.Errors(JudgmentBundleSchema, parsed));
  if (errors.length > 0) {
    return Effect.fail(
      new BundleDecodeError({
        cause: BundleDecodeCause.SchemaInvalid({
          path: originPath,
          errors,
        }),
      }),
    );
  }
  const decoded = Value.Decode(JudgmentBundleSchema, parsed);
  return Effect.succeed(normalizeBundle(decoded));
}

function normalizeBundle(decoded: JudgmentBundleStatic): JudgmentBundleType {
  return {
    runId: RunId(decoded.runId),
    project: ProjectId(decoded.project),
    scenarioId: ScenarioId(decoded.scenarioId),
    name: decoded.name,
    description: decoded.description,
    requirements: decoded.requirements,
    agents: decoded.agents.map(normalizeAgentRef),
    ...(decoded.turns !== undefined ? { turns: decoded.turns.map(normalizeTurn) } : {}),
    ...(decoded.events !== undefined ? { events: decoded.events } : {}),
    ...(decoded.phases !== undefined ? { phases: decoded.phases } : {}),
    ...(decoded.context !== undefined ? { context: decoded.context } : {}),
    ...(decoded.workspaceDiff !== undefined ? { workspaceDiff: decoded.workspaceDiff } : {}),
    outcomes: decoded.outcomes.map(normalizeOutcome),
    ...(decoded.metadata !== undefined ? { metadata: decoded.metadata } : {}),
  };
}

function normalizeAgentRef(agent: AgentRef): AgentRef {
  return { ...agent };
}

function normalizeTurn(turn: NonNullable<JudgmentBundleStatic["turns"]>[number]): AgentTurn {
  return {
    turn: turn.turn,
    ...(turn.agentId !== undefined ? { agentId: AgentId(turn.agentId) } : {}),
  };
}

function normalizeOutcome(outcome: JudgmentBundleStatic["outcomes"][number]): AgentOutcome {
  return {
    ...outcome,
    agentId: AgentId(outcome.agentId),
  };
}

function decodeJson(source: string, originPath: string): Effect.Effect<JudgmentBundleType, BundleDecodeError, never> {
  return Effect.try({
    try: () => JSON.parse(source),
    catch: (error) =>
      new BundleDecodeError({
        cause: BundleDecodeCause.SchemaInvalid({
          path: originPath,
          errors: [error instanceof Error ? error.message : String(error)],
        }),
      }),
  }).pipe(Effect.flatMap((parsed) => decodeFromParsed(parsed, originPath)));
}

function decodeYaml(source: string, originPath: string): Effect.Effect<JudgmentBundleType, BundleDecodeError, never> {
  return Effect.try({
    try: () => YAML.parse(source),
    catch: (error) =>
      new BundleDecodeError({
        cause: BundleDecodeCause.SchemaInvalid({
          path: originPath,
          errors: [error instanceof Error ? error.message : String(error)],
        }),
      }),
  }).pipe(Effect.flatMap((parsed) => decodeFromParsed(parsed, originPath)));
}

function encodeJson(bundle: JudgmentBundleType): Effect.Effect<string, never, never> {
  return Effect.sync(() => JSON.stringify(bundle, null, 2));
}

function encodeYaml(bundle: JudgmentBundleType): Effect.Effect<string, never, never> {
  return Effect.sync(() => YAML.stringify(bundle));
}

export const bundleJsonCodec: BundleCodec = {
  name: "json",
  encode: encodeJson,
  decode: decodeJson,
};

export const bundleYamlCodec: BundleCodec = {
  name: "yaml",
  encode: encodeYaml,
  decode: decodeYaml,
};

export const bundleAutoCodec: BundleCodec = {
  name: "auto",
  encode: encodeJson,
  decode(source, originPath) {
    const trimmed = source.trimStart();
    if (trimmed.startsWith("{") || trimmed.startsWith("[")) {
      return decodeJson(source, originPath);
    }
    return decodeYaml(source, originPath);
  },
};

src/emit/observability.ts.source:
// ObservabilityEmitter interface + BraintrustEmitter + PromptfooEmitter.
// Invariant #12: emission never changes verdict or exit code.
// Spec Q-OBS-1 (A): array of emitters, each failure isolated.
// Spec Q-OBS-2 (C): both per-run (streaming) and per-report (roll-up).

import { Effect } from "effect";
import { writeFileSync, mkdirSync } from "node:fs";
import * as path from "node:path";
import { initLogger, type Logger as BraintrustLogger } from "braintrust";
import type { Report, RunRecord } from "../core/schema.js";

export interface ObservabilityEvent {
  readonly record: RunRecord;
}

export interface ObservabilityReport {
  readonly report: Report;
}

export interface ObservabilityEmitter {
  readonly name: string;
  onRun(event: ObservabilityEvent): Effect.Effect<void, never, never>;
  onReport(event: ObservabilityReport): Effect.Effect<void, never, never>;
}

// -------------------- BraintrustEmitter --------------------

export interface BraintrustEmitterOpts {
  readonly project: string;
  readonly apiKey: string;
  readonly experimentName?: string;
}

export class BraintrustEmitter implements ObservabilityEmitter {
  readonly name = "braintrust";
  readonly #opts: BraintrustEmitterOpts;
  #logger: BraintrustLogger<true> | null = null;

  constructor(opts: BraintrustEmitterOpts) {
    this.#opts = opts;
  }

  #ensureLogger(): BraintrustLogger<true> {
    if (this.#logger !== null) return this.#logger;
    this.#logger = initLogger({
      apiKey: this.#opts.apiKey,
      projectName: this.#opts.project,
    });
    return this.#logger;
  }

  onRun(event: ObservabilityEvent): Effect.Effect<void, never, never> {
    return Effect.sync(() => {
      try {
        const logger = this.#ensureLogger();
        logger.log({
          input: { scenarioId: event.record.scenarioId, source: event.record.source },
          output: { pass: event.record.pass, reason: event.record.reason },
          scores: { pass: event.record.pass ? 1 : 0 },
          metadata: {
            runNumber: event.record.runNumber,
            modelName: event.record.modelName,
            judgeModel: event.record.judgeModel,
            latencyMs: event.record.latencyMs,
            retryCount: event.record.retryCount,
            toolCallCount: event.record.toolCallCount,
            inputTokens: event.record.inputTokens,
            outputTokens: event.record.outputTokens,
            overallSeverity: event.record.overallSeverity ?? "none",
            ...(event.record.failureKind !== undefined && event.record.failureKind !== null
              ? { failureKind: event.record.failureKind }
              : {}),
          },
        });
      } catch (err) {
        void err;
        // Invariant #12: observability never affects verdict. Drop and move on.
      }
    });
  }

  onReport(_event: ObservabilityReport): Effect.Effect<void, never, never> {
    void _event;
    return Effect.tryPromise({
      try: () => this.#flushLogger(),
      catch: () => null,
    }).pipe(
      Effect.catchAll(() => Effect.void),
      Effect.asVoid,
    );
  }

  #flushLogger() {
    if (this.#logger === null) return Promise.resolve();
    const p = this.#logger.flush();
    return p instanceof Promise ? p : Promise.resolve();
  }
}

// -------------------- PromptfooEmitter --------------------

export interface PromptfooEmitterOpts {
  readonly outputPath: string;
}

export class PromptfooEmitter implements ObservabilityEmitter {
  readonly name = "promptfoo";
  readonly #outputPath: string;

  constructor(opts: PromptfooEmitterOpts) {
    this.#outputPath = opts.outputPath;
  }

  onRun(_event: ObservabilityEvent): Effect.Effect<void, never, never> {
    // Promptfoo's dashboard ingests a single-file results.json (one roll-up
    // per pipeline). We defer to onReport.
    void _event;
    return Effect.void;
  }

  onReport(event: ObservabilityReport): Effect.Effect<void, never, never> {
    return Effect.sync(() => {
      try {
        const payload = toPromptfooResults(event.report);
        const abs = path.resolve(this.#outputPath);
        mkdirSync(path.dirname(abs), { recursive: true });
        writeFileSync(abs, JSON.stringify(payload, null, 2), "utf8");
      } catch (err) {
        void err;
        // Invariant #12.
      }
    });
  }
}

interface PromptfooResultRow {
  readonly promptId: string;
  readonly testIdx: number;
  readonly success: boolean;
  readonly score: number;
  readonly latencyMs: number;
  readonly response: {
    readonly output: string;
    readonly tokenUsage: { readonly prompt: number; readonly completion: number; readonly cached: number };
  };
  readonly gradingResult: { readonly pass: boolean; readonly score: number; readonly reason: string };
  readonly vars: Readonly<Record<string, string | number | boolean>>;
}

function toPromptfooResults(report: Report): {
  readonly version: 3;
  readonly createdAt: string;
  readonly results: {
    readonly timestamp: string;
    readonly results: ReadonlyArray<PromptfooResultRow>;
    readonly stats: {
      readonly successes: number;
      readonly failures: number;
      readonly tokenUsage: { readonly total: number; readonly prompt: number; readonly completion: number };
    };
  };
} {
  const now = new Date().toISOString();
  const rows: PromptfooResultRow[] = report.runs.map((r, i) => ({
    promptId: r.scenarioId,
    testIdx: i,
    success: r.pass,
    score: r.pass ? 1 : 0,
    latencyMs: r.latencyMs,
    response: {
      output: r.reason,
      tokenUsage: {
        prompt: r.inputTokens,
        completion: r.outputTokens,
        cached: r.cacheReadTokens,
      },
    },
    gradingResult: { pass: r.pass, score: r.pass ? 1 : 0, reason: r.reason },
    vars: {
      scenarioId: r.scenarioId,
      runNumber: r.runNumber,
      source: r.source,
    },
  }));
  let totalPrompt = 0;
  let totalCompletion = 0;
  for (const r of report.runs) {
    totalPrompt += r.inputTokens;
    totalCompletion += r.outputTokens;
  }
  return {
    version: 3,
    createdAt: now,
    results: {
      timestamp: now,
      results: rows,
      stats: {
        successes: report.summary.passed,
        failures: report.summary.failed,
        tokenUsage: {
          total: totalPrompt + totalCompletion,
          prompt: totalPrompt,
          completion: totalCompletion,
        },
      },
    },
  };
}

src/emit/report.ts.source:
// Report emitter: writes the summary.md + results.jsonl + details/*.yaml triple,
// and optionally posts a GitHub comment.
// Invariant #12: emission never changes verdicts. Every filesystem failure is
// swallowed on the hot path so a disk blip doesn't flip run outcomes.

import { Effect } from "effect";
import { Value } from "@sinclair/typebox/value";
import { mkdirSync, appendFileSync, writeFileSync, existsSync, unlinkSync, readFileSync } from "node:fs";
import { execFileSync } from "node:child_process";
import * as path from "node:path";
import * as YAML from "yaml";
import { PublishError, PublishErrorCause } from "../core/errors.js";
import { RunRecordSchema, type Report, type RunRecord } from "../core/schema.js";
import { ScenarioId, RunNumber } from "../core/types.js";

export interface ReportEmitterOpts {
  readonly resultsDir: string;
  readonly githubComment?: number;
  readonly githubCommentArtifactUrl?: string;
}

export interface ReportEmitter {
  emitRun(record: RunRecord): Effect.Effect<void, never, never>;
  emitReport(report: Report): Effect.Effect<void, never, never>;
  publishGithubComment(report: Report): Effect.Effect<void, PublishError, never>;
}

const GITHUB_COMMENT_BODY_LIMIT = 65_000;

function ensureDir(dir: string): void {
  mkdirSync(dir, { recursive: true });
}

function runFilename(record: RunRecord): string {
  const safeId = record.scenarioId.replace(/[^A-Za-z0-9_-]/gu, "_");
  return `${safeId}.${String(record.runNumber)}.yaml`;
}

function renderSummary(report: Report): string {
  const { summary } = report;
  const lines: string[] = [];
  lines.push("# cc-judge report");
  lines.push("");
  lines.push(`- total: ${String(summary.total)}`);
  lines.push(`- passed: ${String(summary.passed)}`);
  lines.push(`- failed: ${String(summary.failed)}`);
  lines.push(`- avg latency: ${summary.avgLatencyMs.toFixed(0)}ms`);
  if (report.artifactsDir !== undefined) {
    lines.push(`- artifacts: ${report.artifactsDir}`);
  }
  lines.push("");
  lines.push("## Runs");
  lines.push("");
  lines.push("| scenario | run | verdict | severity | latency | retries |");
  lines.push("| --- | --- | --- | --- | --- | --- |");
  for (const r of report.runs) {
    const verdict = r.pass ? "PASS" : "FAIL";
    const severity = r.overallSeverity ?? "-";
    lines.push(
      `| ${r.scenarioId} | ${String(r.runNumber)} | ${verdict} | ${severity} | ${String(r.latencyMs)}ms | ${String(r.retryCount)} |`,
    );
  }
  lines.push("");
  lines.push("## Failures");
  lines.push("");
  const failures = report.runs.filter((r) => !r.pass);
  if (failures.length === 0) {
    lines.push("None.");
  } else {
    for (const r of failures) {
      lines.push(`### ${r.scenarioId} #${String(r.runNumber)}`);
      lines.push(`- reason: ${r.reason}`);
      if (r.issues.length > 0) {
        lines.push("- issues:");
        for (const i of r.issues) {
          lines.push(`  - [${i.severity}] ${i.issue}`);
        }
      }
      lines.push("");
    }
  }
  return lines.join("\n");
}

function truncateForGitHub(body: string, artifactUrl: string | undefined): string {
  if (body.length <= GITHUB_COMMENT_BODY_LIMIT) return body;
  const prefix = body.slice(0, GITHUB_COMMENT_BODY_LIMIT - 500);
  const suffix = artifactUrl !== undefined
    ? `\n\n…truncated. Full report: ${artifactUrl}`
    : "\n\n…truncated (raise --github-comment-artifact-url to link the full report).";
  return prefix + suffix;
}

function ghAvailable(): boolean {
  try {
    execFileSync("gh", ["--version"], { stdio: "ignore" });
    return true;
  } catch (err) {
    void err;
    return false;
  }
}

function postGithubComment(prNumber: number, body: string): Effect.Effect<void, PublishError, never> {
  return Effect.suspend(() => {
    if (!ghAvailable()) {
      return Effect.fail(new PublishError({ cause: PublishErrorCause.GhCliMissing() }));
    }
    return Effect.tryPromise({
      try: () => runGh(prNumber, body),
      catch: (err) =>
        new PublishError({
          cause: PublishErrorCause.GhCliFailed({
            exitCode: 1,
            stderr: err instanceof Error ? err.message : String(err),
          }),
        }),
    });
  });
}

function runGh(prNumber: number, body: string) {
  return new Promise<void>((resolve, reject) => {
    try {
      execFileSync("gh", ["pr", "comment", String(prNumber), "--body-file", "-"], {
        input: body,
        stdio: ["pipe", "ignore", "pipe"],
      });
      resolve();
    } catch (err) {
      reject(err instanceof Error ? err : new Error(String(err)));
    }
  });
}

export function makeReportEmitter(opts: ReportEmitterOpts): ReportEmitter {
  const resultsDir = path.resolve(opts.resultsDir);
  const detailsDir = path.join(resultsDir, "details");
  const jsonlPath = path.join(resultsDir, "results.jsonl");
  const summaryPath = path.join(resultsDir, "summary.md");

  return {
    emitRun(record) {
      return Effect.sync(() => {
        try {
          ensureDir(detailsDir);
          appendFileSync(jsonlPath, `${JSON.stringify(record)}\n`, "utf8");
          const yamlPath = path.join(detailsDir, runFilename(record));
          writeFileSync(yamlPath, YAML.stringify(record), "utf8");
        } catch (err) {
          void err;
          // Emission is non-verdict. Drop and move on (invariant #12).
        }
      });
    },

    emitReport(report) {
      return Effect.sync(() => {
        try {
          ensureDir(resultsDir);
          // Rewrite results.jsonl from the finalized record list. The streaming
          // emitRun path is best-effort; the report is the canonical form.
          if (existsSync(jsonlPath)) unlinkSync(jsonlPath);
          const jsonl = report.runs.map((r) => JSON.stringify(r)).join("\n");
          writeFileSync(jsonlPath, jsonl.length > 0 ? `${jsonl}\n` : "", "utf8");
          writeFileSync(summaryPath, renderSummary(report), "utf8");
          ensureDir(detailsDir);
          for (const r of report.runs) {
            writeFileSync(path.join(detailsDir, runFilename(r)), YAML.stringify(r), "utf8");
          }
        } catch (err) {
          void err;
          // See emitRun comment. Verdict data is already in Report; disk is secondary.
        }
      });
    },

    publishGithubComment(report) {
      const prNumber = opts.githubComment;
      if (prNumber === undefined) return Effect.void;
      const body = truncateForGitHub(renderSummary(report), opts.githubCommentArtifactUrl);
      return postGithubComment(prNumber, body);
    },
  };
}

// Helper: read an existing jsonl back into RunRecord[] for report consumers.
export function readRunsJsonl(resultsDir: string): ReadonlyArray<RunRecord> {
  const jsonlPath = path.join(path.resolve(resultsDir), "results.jsonl");
  if (!existsSync(jsonlPath)) return [];
  const raw = readFileSync(jsonlPath, "utf8");
  const out: RunRecord[] = [];
  for (const line of raw.split("\n")) {
    const trimmed = line.trim();
    if (trimmed.length === 0) continue;
    let parsed: unknown;
    try {
      parsed = JSON.parse(trimmed);
    } catch (err) {
      void err;
      // Skip malformed line; inflight-crash recovery is best-effort.
      continue;
    }
    if (!Value.Check(RunRecordSchema, parsed)) continue;
    const decoded = Value.Decode(RunRecordSchema, parsed);
    const { scenarioId: rawScenarioId, runNumber: rawRunNumber, ...rest } = decoded;
    const record: RunRecord = {
      ...rest,
      scenarioId: ScenarioId(rawScenarioId),
      runNumber: RunNumber(rawRunNumber),
    };
    out.push(record);
  }
  return out;
}

