import { describe, expect, vi } from "vitest";
import { Deferred, Effect, Exit } from "effect";
import { DefaultRunCoordinator, PromptWorkspaceHarness, type AgentRuntime, type RuntimeHandle } from "../src/runner/index.js";
import { HarnessExecutionCause, HarnessExecutionError } from "../src/core/errors.js";
import {
  AgentId,
  ProjectId,
  ScenarioId,
  type AgentDeclaration,
  type RunPlan,
  type Turn,
  type WorkspaceDiff,
} from "../src/core/types.js";
import { itEffect } from "./support/effect.js";

function makePlan(): RunPlan {
  const agents: readonly [AgentDeclaration, AgentDeclaration] = [
    {
      id: AgentId("agent-1"),
      name: "Agent One",
      artifact: { _tag: "DockerImageArtifact", image: "repo/agent-one:latest" },
      promptInputs: {},
    },
    {
      id: AgentId("agent-2"),
      name: "Agent Two",
      artifact: { _tag: "DockerImageArtifact", image: "repo/agent-two:latest" },
      promptInputs: {},
    },
  ];
  return {
    project: ProjectId("cc-judge"),
    scenarioId: ScenarioId("multi-agent"),
    name: "multi-agent",
    description: "multi-agent prompt harness",
    agents,
    requirements: {
      expectedBehavior: "both agents respond",
      validationChecks: ["each agent emits one response"],
    },
  };
}

function makeSingleAgentPlan(): RunPlan {
  const [agent] = makePlan().agents;
  if (agent === undefined) {
    throw new Error("missing agent fixture");
  }
  return {
    ...makePlan(),
    agents: [agent],
    scenarioId: ScenarioId("single-agent"),
    name: "single-agent",
    description: "single-agent prompt harness",
  };
}

class FakeRuntime implements AgentRuntime {
  readonly kind = "docker" as const;
  readonly stopped: string[] = [];

  prepare(agent: AgentDeclaration): Effect.Effect<RuntimeHandle, never, never> {
    const diff: WorkspaceDiff = {
      changed: [{ path: `${agent.id}.txt`, before: null, after: agent.name }],
    };
    return Effect.succeed({
      agent,
      kind: "docker",
      workspaceDir: `/tmp/${agent.id}`,
      writeWorkspace() {
        return Effect.void;
      },
      executePrompt(prompt: string): Effect.Effect<Turn, never, never> {
        const startedAt = agent.id === "agent-1"
          ? "2026-04-19T00:00:02.000Z"
          : "2026-04-19T00:00:01.000Z";
        return Effect.succeed({
          index: 0,
          prompt,
          response: `${agent.name} handled ${prompt}`,
          startedAt,
          latencyMs: 10,
          toolCallCount: 0,
          inputTokens: 2,
          outputTokens: 3,
          cacheReadTokens: 0,
          cacheWriteTokens: 0,
        });
      },
      diffWorkspace() {
        return Effect.succeed(diff);
      },
    });
  }

  stop(handle: RuntimeHandle): Effect.Effect<void, never, never> {
    return Effect.sync(() => {
      this.stopped.push(handle.agent.id);
    });
  }
}

class AbortAwareRuntime implements AgentRuntime {
  readonly kind = "docker" as const;
  readonly stopped: string[] = [];
  seenAbortSignal: AbortSignal | undefined;
  aborted = false;
  readonly #promptReady: Deferred.Deferred<void, never>;

  constructor(promptReady: Deferred.Deferred<void, never>) {
    this.#promptReady = promptReady;
  }

  get promptReady(): Deferred.Deferred<void, never> {
    return this.#promptReady;
  }

  prepare(agent: AgentDeclaration): Effect.Effect<RuntimeHandle, never, never> {
    const runtime = this;
    return Effect.succeed({
      agent,
      kind: "docker",
      workspaceDir: `/tmp/${agent.id}`,
      writeWorkspace() {
        return Effect.void;
      },
      executePrompt(_prompt: string, opts: { readonly timeoutMs: number; readonly abortSignal?: AbortSignal }): Effect.Effect<Turn, HarnessExecutionError, never> {
        void opts.timeoutMs;
        return Effect.async((resume) => {
          runtime.seenAbortSignal = opts.abortSignal;
          const onAbort = () => {
            runtime.aborted = true;
            resume(
              Effect.fail(
                new HarnessExecutionError({
                  cause: HarnessExecutionCause.ExecutionFailed({
                    message: "aborted",
                  }),
                }),
              ),
            );
          };
          if (opts.abortSignal?.aborted === true) {
            onAbort();
            return Effect.void;
          }
          opts.abortSignal?.addEventListener("abort", onAbort, { once: true });
          Effect.runSync(Deferred.succeed(runtime.#promptReady, undefined));
          return Effect.sync(() => {
            opts.abortSignal?.removeEventListener("abort", onAbort);
          });
        });
      },
      diffWorkspace() {
        return Effect.succeed({ changed: [] });
      },
    });
  }

  stop(handle: RuntimeHandle): Effect.Effect<void, never, never> {
    return Effect.sync(() => {
      this.stopped.push(handle.agent.id);
    });
  }
}

describe("DefaultRunCoordinator + PromptWorkspaceHarness", () => {
  itEffect("coordinates a multi-agent run and emits a normalized bundle", function* () {
    const runtime = new FakeRuntime();
    const coordinator = new DefaultRunCoordinator(runtime);
    const harness = new PromptWorkspaceHarness({
      prompts: ["solve"],
      workspace: [{ path: "README.md", content: "seed" }],
    });

    const bundle = yield* coordinator.execute(makePlan(), harness);

    expect(bundle.agents).toHaveLength(2);
    expect(bundle.outcomes).toHaveLength(2);
    expect(bundle.turns).toHaveLength(2);
    expect(bundle.events).toHaveLength(4);
    const expectedEventTimestamps = [
      Date.parse("2026-04-19T00:00:01.000Z"),
      Date.parse("2026-04-19T00:00:01.000Z") + 10,
      Date.parse("2026-04-19T00:00:02.000Z"),
      Date.parse("2026-04-19T00:00:02.000Z") + 10,
    ];
    expect(bundle.events?.map((event) => event.ts)).toEqual([
      ...expectedEventTimestamps,
    ]);
    expect(bundle.context).toMatchObject({
      workspaceDiffByAgent: {
        "agent-1": { changed: [{ path: "agent-1.txt", before: null, after: "Agent One" }] },
        "agent-2": { changed: [{ path: "agent-2.txt", before: null, after: "Agent Two" }] },
      },
    });
    expect(runtime.stopped.sort()).toEqual(["agent-1", "agent-2"]);
  });

  itEffect("assigns unique run IDs even when Date.now is constant", function* () {
    const runtime = new FakeRuntime();
    const coordinator = new DefaultRunCoordinator(runtime);
    const harness = new PromptWorkspaceHarness({
      prompts: ["solve"],
      workspace: [{ path: "README.md", content: "seed" }],
    });
    const nowSpy = vi.spyOn(Date, "now").mockReturnValue(1_726_000_000_000);
    try {
      const first = yield* coordinator.execute(makePlan(), harness);
      const second = yield* coordinator.execute(makePlan(), harness);
      expect(first.runId).not.toBe(second.runId);
    } finally {
      nowSpy.mockRestore();
    }
  });

  itEffect("forwards abort signals into the live prompt path", function* () {
    const promptReady = yield* Deferred.make<void>();
    const runtime = new AbortAwareRuntime(promptReady);
    const coordinator = new DefaultRunCoordinator(runtime);
    const harness = new PromptWorkspaceHarness({
      prompts: ["wait"],
      workspace: [{ path: "README.md", content: "seed" }],
    });
    const abortController = new AbortController();
    const fiber = yield* Effect.fork(coordinator.execute(makeSingleAgentPlan(), harness, {
      abortSignal: abortController.signal,
    }));

    yield* Deferred.await(promptReady);
    expect(runtime.seenAbortSignal).toBe(abortController.signal);
    abortController.abort();

    const exit = yield* fiber.await;
    expect(runtime.seenAbortSignal).toBe(abortController.signal);
    expect(runtime.aborted).toBe(true);
    expect(Exit.isFailure(exit)).toBe(true);
  });
});

tests/judge-preflight-formatter.test.ts.source:
// Targeted formatter tests for `formatJudgePreflightMessage`.
//
// The strings here ARE the CLI contract (`cc-judge: ...` printed to stderr
// on preflight failure). Pinning them in this dedicated formatter test
// lets tests/judge-preflight.test.ts assert on JudgePreflightResult tags
// structurally without losing mutation coverage on the user-visible copy.
//
// PBT covers the only meaningful input axis (the `detail` string on
// PreflightFailed and InvalidJson); examples pin every exact phrase.

import { describe, expect, it } from "vitest";
import * as fc from "fast-check";
import {
  JUDGE_PREFLIGHT_TAG,
  JudgePreflightResult,
  formatJudgePreflightMessage,
} from "../src/app/judge-preflight.js";

const PROPERTY_RUNS = 100;

describe("formatJudgePreflightMessage", () => {
  it("Ready returns null (no message printed)", () => {
    expect(formatJudgePreflightMessage(JudgePreflightResult.Ready())).toBeNull();
  });

  describe("PreflightFailed", () => {
    it("with non-empty detail: 'claude auth preflight failed: <detail>'", () => {
      const detail = "spawn ENOENT";
      expect(
        formatJudgePreflightMessage(JudgePreflightResult.PreflightFailed({ detail })),
      ).toBe(`claude auth preflight failed: ${detail}`);
    });

    it("with empty detail: 'claude auth preflight failed' (no trailing colon)", () => {
      expect(
        formatJudgePreflightMessage(JudgePreflightResult.PreflightFailed({ detail: "" })),
      ).toBe("claude auth preflight failed");
    });

    it("PBT: any non-empty detail roundtrips into the suffixed form", () => {
      fc.assert(
        fc.property(
          fc.string({ minLength: 1, maxLength: 200 }).filter((s) => !s.includes("\n")),
          (detail) => {
            const out = formatJudgePreflightMessage(
              JudgePreflightResult.PreflightFailed({ detail }),
            );
            expect(out).toBe(`claude auth preflight failed: ${detail}`);
          },
        ),
        { numRuns: PROPERTY_RUNS },
      );
    });

    it("PBT: every PreflightFailed message starts with the canonical prefix", () => {
      fc.assert(
        fc.property(fc.string({ maxLength: 200 }), (detail) => {
          const out = formatJudgePreflightMessage(
            JudgePreflightResult.PreflightFailed({ detail }),
          );
          expect(out?.startsWith("claude auth preflight failed")).toBe(true);
        }),
        { numRuns: PROPERTY_RUNS },
      );
    });
  });

  describe("AuthMissing", () => {
    const message = formatJudgePreflightMessage(JudgePreflightResult.AuthMissing());

    it("starts with 'claude auth missing'", () => {
      expect(message?.startsWith("claude auth missing")).toBe(true);
    });

    it("instructs the user to run `claude auth login`", () => {
      expect(message).toContain("`claude auth login`");
    });

    it("mentions the ANTHROPIC_API_KEY env-var fallback", () => {
      expect(message).toContain("ANTHROPIC_API_KEY");
    });

    it("renders the full canonical sentence", () => {
      expect(message).toBe(
        "claude auth missing: run `claude auth login` or set ANTHROPIC_API_KEY",
      );
    });
  });

  describe("InvalidJson", () => {
    it("with non-empty detail: 'claude auth preflight returned invalid JSON: <detail>'", () => {
      const detail = "Unexpected token } in JSON at position 17";
      expect(
        formatJudgePreflightMessage(JudgePreflightResult.InvalidJson({ detail })),
      ).toBe(`claude auth preflight returned invalid JSON: ${detail}`);
    });

    it("with empty detail: 'claude auth preflight returned invalid JSON' (no trailing colon)", () => {
      expect(
        formatJudgePreflightMessage(JudgePreflightResult.InvalidJson({ detail: "" })),
      ).toBe("claude auth preflight returned invalid JSON");
    });

    it("PBT: any non-empty detail roundtrips into the suffixed form", () => {
      fc.assert(
        fc.property(
          fc.string({ minLength: 1, maxLength: 200 }).filter((s) => !s.includes("\n")),
          (detail) => {
            const out = formatJudgePreflightMessage(
              JudgePreflightResult.InvalidJson({ detail }),
            );
            expect(out).toBe(`claude auth preflight returned invalid JSON: ${detail}`);
          },
        ),
        { numRuns: PROPERTY_RUNS },
      );
    });

    it("PBT: every InvalidJson message starts with the canonical prefix", () => {
      fc.assert(
        fc.property(fc.string({ maxLength: 200 }), (detail) => {
          const out = formatJudgePreflightMessage(
            JudgePreflightResult.InvalidJson({ detail }),
          );
          expect(out?.startsWith("claude auth preflight returned invalid JSON")).toBe(true);
        }),
        { numRuns: PROPERTY_RUNS },
      );
    });
  });

  describe("PBT: cross-tag invariants", () => {
    const tagArb = fc.constantFrom(
      JUDGE_PREFLIGHT_TAG.Ready,
      JUDGE_PREFLIGHT_TAG.PreflightFailed,
      JUDGE_PREFLIGHT_TAG.AuthMissing,
      JUDGE_PREFLIGHT_TAG.InvalidJson,
    );

    function build(tag: string, detail: string) {
      switch (tag) {
        case JUDGE_PREFLIGHT_TAG.Ready: return JudgePreflightResult.Ready();
        case JUDGE_PREFLIGHT_TAG.PreflightFailed:
          return JudgePreflightResult.PreflightFailed({ detail });
        case JUDGE_PREFLIGHT_TAG.AuthMissing: return JudgePreflightResult.AuthMissing();
        case JUDGE_PREFLIGHT_TAG.InvalidJson:
          return JudgePreflightResult.InvalidJson({ detail });
        default: throw new Error(`unknown tag ${tag}`);
      }
    }

    it("Ready ↔ null is the only null-returning branch", () => {
      fc.assert(
        fc.property(tagArb, fc.string({ maxLength: 50 }), (tag, detail) => {
          const out = formatJudgePreflightMessage(build(tag, detail));
          if (tag === JUDGE_PREFLIGHT_TAG.Ready) {
            expect(out).toBeNull();
          } else {
            expect(out).not.toBeNull();
            expect((out as string).length).toBeGreaterThan(0);
          }
        }),
        { numRuns: PROPERTY_RUNS },
      );
    });

    it("non-Ready messages are single-line (no embedded newlines)", () => {
      fc.assert(
        fc.property(
          tagArb.filter((t) => t !== JUDGE_PREFLIGHT_TAG.Ready),
          fc.string({ maxLength: 50 }).filter((s) => !s.includes("\n")),
          (tag, detail) => {
            const out = formatJudgePreflightMessage(build(tag, detail));
            expect(out).not.toBeNull();
            expect((out as string).includes("\n")).toBe(false);
          },
        ),
        { numRuns: PROPERTY_RUNS },
      );
    });
  });

  describe("tag map matches the runtime constructors", () => {
    it("Ready", () => {
      expect(JudgePreflightResult.Ready()._tag).toBe(JUDGE_PREFLIGHT_TAG.Ready);
    });
    it("PreflightFailed", () => {
      expect(JudgePreflightResult.PreflightFailed({ detail: "x" })._tag)
        .toBe(JUDGE_PREFLIGHT_TAG.PreflightFailed);
    });
    it("AuthMissing", () => {
      expect(JudgePreflightResult.AuthMissing()._tag).toBe(JUDGE_PREFLIGHT_TAG.AuthMissing);
    });
    it("InvalidJson", () => {
      expect(JudgePreflightResult.InvalidJson({ detail: "x" })._tag)
        .toBe(JUDGE_PREFLIGHT_TAG.InvalidJson);
    });
  });
});

